from __future__ import annotations

import difflib

from textual.widgets import Static
from rich.text import Text


class DiffDisplay(Static):
    """Widget for displaying unified diffs with syntax highlighting.

    Shows added lines in green and removed lines in red,
    with context lines in the default color.
    """

    DEFAULT_CSS = """
    DiffDisplay {
        height: auto;
        padding: 0 1;
        margin: 0 0 1 0;
    }
    """

    def __init__(
        self,
        old_text: str = "",
        new_text: str = "",
        filename: str = "",
        *,
        name: str | None = None,
        id: str | None = None,
        classes: str | None = None,
    ) -> None:
        super().__init__("", name=name, id=id, classes=classes)
        self._old_text = old_text
        self._new_text = new_text
        self._filename = filename

    def on_mount(self) -> None:
        """Render the diff on mount."""
        if self._old_text or self._new_text:
            self.show_diff(self._old_text, self._new_text, self._filename)

    def show_diff(
        self, old_text: str, new_text: str, filename: str = ""
    ) -> None:
        """Generate and display a unified diff.

        Args:
            old_text: Original file content.
            new_text: Modified file content.
            filename: File name for the diff header.
        """
        old_lines = old_text.splitlines(keepends=True)
        new_lines = new_text.splitlines(keepends=True)

        diff = difflib.unified_diff(
            old_lines,
            new_lines,
            fromfile=f"a/{filename}" if filename else "a/file",
            tofile=f"b/{filename}" if filename else "b/file",
            lineterm="",
        )

        text = Text()
        for line in diff:
            stripped = line.rstrip("\n")
            if stripped.startswith("+++") or stripped.startswith("---"):
                text.append(stripped + "\n", style="bold")
            elif stripped.startswith("@@"):
                text.append(stripped + "\n", style="cyan")
            elif stripped.startswith("+"):
                text.append(stripped + "\n", style="green")
            elif stripped.startswith("-"):
                text.append(stripped + "\n", style="red")
            else:
                text.append(stripped + "\n")

        if not text.plain.strip():
            text.append("(no changes)", style="dim")

        self.update(text)

    def show_raw_diff(self, diff_text: str) -> None:
        """Display a pre-formatted diff string.

        Args:
            diff_text: Raw diff text (e.g., from git diff).
        """
        text = Text()
        for line in diff_text.splitlines():
            if line.startswith("+++") or line.startswith("---"):
                text.append(line + "\n", style="bold")
            elif line.startswith("@@"):
                text.append(line + "\n", style="cyan")
            elif line.startswith("+"):
                text.append(line + "\n", style="green")
            elif line.startswith("-"):
                text.append(line + "\n", style="red")
            elif line.startswith("diff "):
                text.append(line + "\n", style="bold yellow")
            else:
                text.append(line + "\n")

        self.update(text)

