from textual import events
from textual.message import Message
from textual.widgets import TextArea


class UserInput(TextArea):
    """Text input widget with slash command detection and history.

    Supports:
    - Enter to submit
    - Slash command detection (/help, /model, etc.)
    - Input history navigation with Up/Down arrows
    """

    DEFAULT_CSS = """
    UserInput {
        height: auto;
        min-height: 1;
        max-height: 8;
        border: none;
        background: $surface;
    }
    UserInput:focus {
        border: none;
    }
    """

    class Submitted(Message):
        """Message sent when user submits input."""

        def __init__(self, value: str) -> None:
            super().__init__()
            self.value = value

    def __init__(
        self,
        *,
        name: str | None = None,
        id: str | None = None,
        classes: str | None = None,
    ) -> None:
        super().__init__(name=name, id=id, classes=classes)
        self._history: list[str] = []
        self._history_index: int = -1

    async def _on_key(self, event: events.Key) -> None:
        """Handle key events for submission and history."""
        if event.key == "enter":
            event.prevent_default()
            event.stop()
            text = self.text.strip()
            if text:
                self._history.append(text)
                self._history_index = -1
                self.clear()
                self.post_message(self.Submitted(text))
        elif event.key == "up" and not self.text:
            # Navigate history backward
            if self._history:
                if self._history_index == -1:
                    self._history_index = len(self._history) - 1
                elif self._history_index > 0:
                    self._history_index -= 1
                self.load_text(self._history[self._history_index])
                event.prevent_default()
        elif event.key == "down" and self._history_index >= 0:
            # Navigate history forward
            if self._history_index < len(self._history) - 1:
                self._history_index += 1
                self.load_text(self._history[self._history_index])
            else:
                self._history_index = -1
                self.clear()
            event.prevent_default()

    @property
    def is_slash_command(self) -> bool:
        """Check if the current input is a slash command."""
        return self.text.strip().startswith("/")

