        name: str | None = None,
        id: str | None = None,
        classes: str | None = None,
    ) -> None:
        super().__init__(
            placeholder="Type a message or /help...",
            name=name,
            id=id,
            classes=classes,
        )
        self._history: list[str] = []
        self._history_index: int = -1

    def on_input_submitted(self, event: Input.Submitted) -> None:
        """Handle Enter key - save history and clear."""
        text = event.value.strip()
        if text:
            self._history.append(text)
            self._history_index = -1
            self.value = ""

    async def _on_key(self, event: events.Key) -> None:
        """Handle Up/Down for history navigation."""
        if event.key == "up" and not self.value:
            if self._history:
                if self._history_index == -1:
                    self._history_index = len(self._history) - 1
                elif self._history_index > 0:
                    self._history_index -= 1
                self.value = self._history[self._history_index]
                event.prevent_default()
        elif event.key == "down" and self._history_index >= 0:
            if self._history_index < len(self._history) - 1:
                self._history_index += 1
                self.value = self._history[self._history_index]
            else:
                self._history_index = -1
                self.value = ""
            event.prevent_default()

    @property
    def is_slash_command(self) -> bool:
        """Check if the current input is a slash command."""
        return self.value.strip().startswith("/")

    @property
    def text(self) -> str:
        """Compatibility property."""
        return self.value

